parameters.jsCode:
const input = $json;

const normalize = (value) =>
  String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();

const getByHint = (hints, fallback = '') => {
  const entries = Object.entries(input);
  for (const hint of hints) {
    const h = normalize(hint);
    const found = entries.find(([k, v]) => normalize(k).includes(h) && v !== undefined && v !== null && String(v).trim() !== '');
    if (found) return String(found[1]).trim();
  }
  return fallback;
};

const problem = getByHint(['problema ou oportunidade', 'problema'], 'Nao informado');
const expectedChange = getByHint(['mudanca como voce espera ver no produto', 'mudanca esperada', 'espera ver no produto'], 'Nao informado');
const evidence = getByHint(['evidencias comprovam que a entrega esta pronta', 'evidencias', 'entrega pronta'], 'Nao informado');
const constraints = getByHint(['restricoes', 'compliance', 'integracoes proibidas', 'limites de prazo'], 'Nenhuma restricao informada');
const deployChoice = getByHint(['deploy api apos aprovacao'], 'nao').toLowerCase();

const fallbackToken = 'COLE_SEU_GITHUB_TOKEN_AQUI';
const envToken = (typeof process !== 'undefined' && process.env && process.env.GITHUB_TOKEN)
  ? String(process.env.GITHUB_TOKEN).trim()
  : '';
const githubToken = String(envToken || fallbackToken)
  .replace(/^Bearer\s+/i, '')
  .replace(/[\r\n\t]/g, '')
  .replace(/[^\x20-\x7E]/g, '')
  .trim();

return [{
  owner: 'oliversoft-tech',
  repo: 'fastroute-changemanagement',
  github_token: githubToken,
  llm_model: 'claude-sonnet-4-5-20250929',
  problem,
  expected_change: expectedChange,
  evidence,
  constraints,
  deploy_api: deployChoice === 'sim',
  domain_ref: 'main',
  api_ref: 'main',
  mobile_ref: 'main',
  mobile_profile: 'preview'
}];

const firstFromNode = (names) => {
  for (const name of names) {
    try {
      const rows = $items(name, 0, 0);
      if (Array.isArray(rows) && rows.length > 0) return rows[0].json || {};
    } catch (_e) {}
  }
  return null;
};

const base = firstFromNode(['Normalize']) || (typeof $json === 'object' && $json ? $json : {});
const raw =
  $json?.text ||
  $json?.response?.text ||
  $json?.choices?.[0]?.message?.content ||
  '';

const fail = (reason, extra = {}) => {
  const details = {
    stage: 'Parse LLM JSON',
    reason,
    raw_type: typeof raw,
    raw_length: typeof raw === 'string' ? raw.length : 0,
    ...extra,
  };
  console.error('[Parse LLM JSON] ' + JSON.stringify(details));
  throw new Error('[Parse LLM JSON] ' + reason + ' | ' + JSON.stringify(details));
};

if (!raw || typeof raw !== 'string' || !raw.trim()) {
  fail('empty_llm_response', {
    available_keys: Object.keys($json || {}),
  });
}

const stripFences = (value) => {
  let txt = String(value || '').replace(/^\uFEFF/, '').trim();
  if (txt.startsWith('```json')) txt = txt.slice(7);
  else if (txt.startsWith('```')) txt = txt.slice(3);
  if (txt.endsWith('```')) txt = txt.slice(0, -3);
  return txt.trim();
};

const cleaned = stripFences(raw);
const parseStrict = (txt) => {
  try {
    return JSON.parse(txt);
  } catch (_e) {
    return null;
  }
};

let parsed = parseStrict(cleaned);
if (!parsed) {
  const firstObj = cleaned.indexOf('{');
  const lastObj = cleaned.lastIndexOf('}');
  if (firstObj >= 0 && lastObj > firstObj) {
    parsed = parseStrict(cleaned.slice(firstObj, lastObj + 1));
  }
}

if (!parsed) {
  const openCurly = (cleaned.match(/\{/g) || []).length;
  const closeCurly = (cleaned.match(/\}/g) || []).length;
  const openSquare = (cleaned.match(/\[/g) || []).length;
  const closeSquare = (cleaned.match(/\]/g) || []).length;
  fail('invalid_json_from_llm', {
    braces_balance: { openCurly, closeCurly, openSquare, closeSquare },
    starts_with: cleaned.slice(0, 220),
    ends_with: cleaned.slice(Math.max(0, cleaned.length - 220)),
  });
}

const first = (...values) => values.find((v) => v !== undefined && v !== null);
const asArray = (value) => {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null || value === '') return [];
  return [value];
};
const asObject = (value) => (value && typeof value === 'object' && !Array.isArray(value) ? value : {});
const asText = (value) => String(value ?? '').trim();

const normalizeChange = (change) => {
  if (typeof change === 'string') {
    return {
      descricao: asText(change),
      testes: [],
      criterios_aceite: []
    };
  }

  const c = asObject(change);
  const descricao = asText(first(c.descricao, c.desc, c.description, ''));
  if (!descricao) {
    fail('change_without_descricao', { change_preview: JSON.stringify(c).slice(0, 250) });
  }

  return {
    descricao,
    testes: asArray(first(c.testes, c.tests, c.test_steps, [])).map((x) => asText(x)).filter(Boolean),
    criterios_aceite: asArray(first(c.criterios_aceite, c.acceptance_criterias, c.acceptance_criteria, [])).map((x) => asText(x)).filter(Boolean)
  };
};

const normalizeImpactRepo = (repoImpact) => {
  const i = asObject(repoImpact);
  const mudancas = asArray(first(i.mudancas, i.changes, [])).map(normalizeChange);
  return {
    impacto: i.impacto === true || i.has_impact === true || i.impact === true,
    mudancas,
    riscos: asArray(first(i.riscos, i.risks, [])).map((x) => asText(x)).filter(Boolean),
    duvidas: asArray(first(i.duvidas, i.doubts, i.questions, [])).map((x) => asText(x)).filter(Boolean),
    itens: asArray(first(i.itens, i.items, [])).map((x) => asText(x)).filter(Boolean)
  };
};

const rawImpacts = asObject(first(parsed?.impactos, parsed?.impacts, parsed?.impact, {}));
if (Object.keys(rawImpacts).length === 0) {
  fail('missing_impacts_object', {
    parsed_keys: Object.keys(asObject(parsed)),
    cleaned_starts_with: cleaned.slice(0, 220),
  });
}

const impacts = {};
for (const [key, value] of Object.entries(rawImpacts)) {
  impacts[key] = normalizeImpactRepo(value);
}

const criteriaMapped = [];
const repoRisks = [];
const repoDoubts = [];
for (const [repoName, info] of Object.entries(impacts)) {
  const impactInfo = asObject(info);
  const changes = asArray(impactInfo.mudancas);
  const riscos = asArray(impactInfo.riscos);
  const duvidas = asArray(impactInfo.duvidas);

  for (const r of riscos) {
    if (r) repoRisks.push(String(r));
  }

  for (const d of duvidas) {
    if (d) repoDoubts.push(String(d));
  }

  for (const change of changes) {
    const c = asObject(change);
    const criterios = asArray(c.criterios_aceite);
    const testes = asArray(c.testes);
    for (const criterio of criterios) {
      criteriaMapped.push({
        criterio: asText(criterio),
        repos: [repoName],
        teste_sugerido: asText(testes[0] || '')
      });
    }
  }
}

const resumo = asText(first(parsed?.resumo, parsed?.summary, parsed?.executive_summary, parsed?.overview, ''));
if (!resumo) {
  fail('missing_resumo', {
    parsed_keys: Object.keys(asObject(parsed)),
  });
}

const normalized = {
  resumo,
  viabilidade: asObject(first(parsed?.viabilidade, parsed?.viability, parsed?.feasibility, {})),
  impactos: impacts,
  criterios_aceite_mapeados: asArray(
    first(
      parsed?.criterios_aceite_mapeados,
      parsed?.acceptance_criteria_mapped,
      parsed?.mapped_acceptance_criteria,
      parsed?.acceptanceCriteriaMapped,
      criteriaMapped
    )
  ),
  riscos: asArray(first(parsed?.riscos, parsed?.risks, parsed?.main_risks, repoRisks)).map((x) => asText(x)).filter(Boolean),
  duvidas: asArray(first(parsed?.duvidas, parsed?.questions, parsed?.open_questions, parsed?.openQuestions, repoDoubts)).map((x) => asText(x)).filter(Boolean)
};

return [{
  ...base,
  analysis: normalized,
  analysis_raw: asObject(parsed),
  llm_raw_text: cleaned
}];

const firstFromNode = (names) => {
  for (const name of names) {
    try {
      const rows = $items(name, 0, 0);
      if (Array.isArray(rows) && rows.length > 0) return rows[0].json || {};
    } catch (_e) {}
  }
  return {};
};

const base = firstFromNode(['Parse LLM JSON2', 'Parse LLM JSON1', 'Parse LLM JSON']);
const impactInsert = firstFromNode(['Insert Impact Analysis2', 'Insert Impact Analysis1', 'Insert Impact Analysis']);
const analysis = (base.analysis && typeof base.analysis === 'object') ? base.analysis : base;
const impacts = (analysis.impactos && typeof analysis.impactos === 'object' && !Array.isArray(analysis.impactos))
  ? analysis.impactos
  : ((analysis.impacts && typeof analysis.impacts === 'object' && !Array.isArray(analysis.impacts)) ? analysis.impacts : {});
const analysisId = impactInsert.id || base.impact_analysis_id || null;

const normalize = (v) => String(v || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/[_\s]+/g, '-')
  .trim();

const asObj = (v) => (v && typeof v === 'object' && !Array.isArray(v) ? v : {});
const toArray = (v) => {
  if (Array.isArray(v)) return v;
  if (v === undefined || v === null || v === '') return [];
  return [v];
};
const toBool = (v) => v === true || String(v || '').toLowerCase() === 'true';
const toSafeNumber = (value) => {
  if (value === undefined || value === null) return NaN;
  const s = String(value).replace(/^\uFEFF/, '').trim();
  if (!s) return NaN;
  const n = Number(s);
  return Number.isFinite(n) ? n : NaN;
};
const short = (v, n = 240) => String(v || '').replace(/\s+/g, ' ').trim().slice(0, n);

const fail = (reason, extra = {}) => {
  const details = {
    stage: 'Build Change Rows',
    reason,
    analysis_id: analysisId,
    impact_keys: Object.keys(impacts || {}),
    ...extra,
  };
  console.error('[Build Change Rows] ' + JSON.stringify(details));
  throw new Error('[Build Change Rows] ' + reason + ' | ' + JSON.stringify(details));
};

const fallbackSignals = [
  /\[fallback\]/i,
  /resposta do llm truncada/i,
  /modelo nao retornou json valido/i,
  /falha ao parsear json do llm/i,
  /executar nova analise/i,
  /revisar analise/i,
  /mudanca sem detalhamento/i,
];
const hasFallbackText = (value) => {
  const txt = String(value || '');
  return fallbackSignals.some((re) => re.test(txt));
};

const normalizeChange = (change, repoName) => {
  if (typeof change === 'string') {
    fail('change_string_not_allowed', { repo: repoName, change_preview: short(change) });
  }

  const c = asObj(change);
  const descricao = String(c.descricao || c.desc || c.description || '').trim();
  const testes = toArray(c.testes || c.tests || c.test_steps).map((x) => String(x || '').trim()).filter(Boolean);
  const criterios = toArray(c.criterios_aceite || c.acceptance_criterias || c.acceptance_criteria).map((x) => String(x || '').trim()).filter(Boolean);
  const explicitCodes = toArray(c.code_changes || c.codeChanges || c.codes || c.code || c.implementacao || c.codigo)
    .map((x) => String(x || '').trim())
    .filter(Boolean);

  if (!descricao) {
    fail('change_without_descricao', { repo: repoName });
  }
  if (hasFallbackText(descricao)) {
    fail('fallback_detected_in_descricao', { repo: repoName, descricao: short(descricao) });
  }
  if (testes.some(hasFallbackText)) {
    fail('fallback_detected_in_testes', { repo: repoName, test_preview: short(testes[0] || '') });
  }

  return {
    descricao,
    testes,
    criterios_aceite: criterios,
    code_changes: explicitCodes,
  };
};

if (!impacts || Object.keys(impacts).length === 0) {
  fail('impacts_empty_from_analysis', {
    analysis_keys: Object.keys(analysis || {}),
    llm_raw_len: String(base.llm_raw_text || '').length,
  });
}

for (const [k, v] of Object.entries(impacts)) {
  const info = asObj(v);
  const mudancas = toArray(info.mudancas || info.changes);
  const riscos = toArray(info.riscos || info.risks);
  const duvidas = toArray(info.duvidas || info.doubts || info.questions);

  if (hasFallbackText(k)) {
    fail('fallback_detected_in_impact_key', { impact_key: short(k) });
  }
  if (mudancas.some((m) => hasFallbackText((m && (m.descricao || m.description)) || ''))) {
    fail('fallback_detected_in_impacts', { impact_key: short(k) });
  }
  if (riscos.some(hasFallbackText) || duvidas.some(hasFallbackText)) {
    fail('fallback_detected_in_risks_or_doubts', { impact_key: short(k) });
  }
}

const impactEntries = Object.entries(asObj(impacts)).map(([k, v]) => ({ key: k, normKey: normalize(k), info: asObj(v) }));
const impactByKey = new Map(impactEntries.map((e) => [e.normKey, e.info]));

const repoRows = $input
  .all()
  .map((i) => i.json || {})
  .map((r) => {
    const repoId = [r.repo_id, r.id, r['\uFEFFid']].map(toSafeNumber).find((n) => Number.isFinite(n) && n > 0);
    const repoName = String(r.name || r.repo_name || r.repository || r.full_name || '').trim();
    if (!Number.isFinite(repoId) || !repoName) return null;
    return { ...r, repo_id: repoId, repo_name: repoName, norm_name: normalize(repoName) };
  })
  .filter(Boolean);

if (repoRows.length === 0) {
  fail('repos_table_empty');
}

const candidatesForRepoName = (repoName) => {
  const n = normalize(repoName);
  const c = [n, n.replaceAll('_', '-'), n.replaceAll('-', '_')];
  if (n.includes('domain')) c.push('fastroute-domain', 'domain');
  if (n.includes('api')) c.push('fastroute-api', 'fastroute_api', 'api');
  if (n.includes('mobile')) c.push('fastroute-mobile-hybrid', 'mobile');
  return [...new Set(c.map(normalize))];
};

const matchImpactForRepo = (repoName) => {
  for (const key of candidatesForRepoName(repoName)) {
    const hit = impactByKey.get(key);
    if (hit) return hit;
  }
  return null;
};

const rowsFromImpact = (repoId, repoName, impactInfo) => {
  const impacted = toBool(impactInfo.impacto) || toBool(impactInfo.impact) || toBool(impactInfo.has_impact);
  if (!impacted) return [];

  const changes = toArray(impactInfo.mudancas || impactInfo.changes).map((c) => normalizeChange(c, repoName));
  if (changes.length === 0) {
    fail('impacted_repo_without_changes', { repo_id: repoId, repo_name: repoName });
  }

  const changeRisks = toArray(impactInfo.riscos || impactInfo.risks).map((x) => String(x || '').trim()).filter(Boolean);
  const changeDoubts = toArray(impactInfo.duvidas || impactInfo.doubts).map((x) => String(x || '').trim()).filter(Boolean);

  if (changeRisks.some(hasFallbackText) || changeDoubts.some(hasFallbackText)) {
    fail('fallback_detected_in_repo_risks_or_doubts', {
      repo_id: repoId,
      repo_name: repoName,
      risk_preview: short(changeRisks[0] || ''),
      doubt_preview: short(changeDoubts[0] || ''),
    });
  }

  const out = [];
  for (const change of changes) {
    const desc = String(change.descricao || '').trim();
    const criteria = toArray(change.criterios_aceite).map((x) => String(x || '').trim()).filter(Boolean);
    const summaryBase = analysisId ? '[impact:' + analysisId + '] ' + desc : desc;
    const summary = criteria.length > 0
      ? summaryBase + ' | criterios_aceite: ' + criteria.join(' | ')
      : summaryBase;

    if (hasFallbackText(summary)) {
      fail('fallback_detected_in_change_summary', { repo_id: repoId, repo_name: repoName, summary: short(summary) });
    }

    const normalizedCodeChanges = toArray(change.code_changes).map((x) => String(x || '').trim()).filter(Boolean);

    out.push({
      repo_id: repoId,
      repo_name: repoName,
      change_summary: summary,
      test_steps: toArray(change.testes).map((x) => String(x || '').trim()).filter(Boolean),
      code_changes: normalizedCodeChanges,
      acceptance_criteria: criteria,
      change_risks: changeRisks,
      change_doubts: changeDoubts,
      impact_analysis_id: analysisId,
    });
  }
  return out;
};

let out = [];
for (const repo of repoRows) {
  const impactInfo = matchImpactForRepo(repo.repo_name);
  if (!impactInfo) continue;
  out.push(...rowsFromImpact(repo.repo_id, repo.repo_name, impactInfo));
}

if (out.length === 0) {
  fail('no_impacted_repo_rows_matched', {
    repos: repoRows.map((r) => r.repo_name),
  });
}

return out.map((json) => ({ json }));

const firstFromNode = (names) => {
  for (const name of names) {
    try {
      const rows = $items(name, 0, 0);
      if (Array.isArray(rows) && rows.length > 0) return rows[0].json || {};
    } catch (_e) {}
  }
  return {};
};

const allFromNode = (names) => {
  for (const name of names) {
    try {
      const rows = $items(name, 0, 0);
      if (Array.isArray(rows) && rows.length > 0) return rows.map((r) => r.json || {});
    } catch (_e) {}
  }
  return [];
};

const asObj = (v) => (v && typeof v === 'object' && !Array.isArray(v) ? v : {});
const toArray = (v) => {
  if (Array.isArray(v)) return v;
  if (v === undefined || v === null || v === '') return [];
  return [v];
};
const toStr = (v) => String(v ?? '').trim();
const toNum = (v) => {
  if (v === undefined || v === null) return NaN;
  const n = Number(String(v).replace(/^\uFEFF/, '').trim());
  return Number.isFinite(n) ? n : NaN;
};
const uniq = (arr) => [...new Set((arr || []).map((x) => toStr(x)).filter(Boolean))];

const base = firstFromNode(['Parse LLM JSON2', 'Parse LLM JSON1', 'Parse LLM JSON']);
const impactInsert = firstFromNode(['Insert Impact Analysis2', 'Insert Impact Analysis1', 'Insert Impact Analysis']);
const analysisBase = asObj(base.analysis);
const existingImpacts = asObj(analysisBase.impactos || analysisBase.impacts || {});

const analysisIdCandidate = impactInsert.id ?? base.impact_analysis_id;
const analysisId = Number.isFinite(toNum(analysisIdCandidate)) ? toNum(analysisIdCandidate) : null;

const repoRows = allFromNode(['Load Repos Table', 'Load Repos Table1', 'Load Repos Table2']);
const changeRows = allFromNode(['Upsert Change In Repo', 'Upsert Change In Repo1', 'Upsert Change In Repo2']);
const testsuiteRows = allFromNode(['Upsert Testsuite For Change (LLM)', 'Upsert Testsuite For Change (LLM)1']);
const testRows = allFromNode(['Upsert Tests For Testsuite (LLM)', 'Upsert Tests For Testsuite (LLM)1']);
const codeChangeRows = allFromNode(['Upsert Code Changes', 'Upsert Code Changes1', 'Upsert Code Changes2']);

const repoNameById = new Map();
for (const row of repoRows) {
  const id = toNum(row.repo_id ?? row.id ?? row['\uFEFFid']);
  const name = toStr(row.name || row.repo_name || row.repository || row.full_name);
  if (Number.isFinite(id) && name) repoNameById.set(id, name);
}

const defaultRepoImpact = () => ({ impacto: false, mudancas: [], riscos: [], duvidas: [] });
const rebuiltImpacts = {};
for (const repoName of repoNameById.values()) {
  rebuiltImpacts[repoName] = defaultRepoImpact();
}

const parseSummary = (summaryRaw) => {
  const raw = toStr(summaryRaw);
  const marker = '| criterios_aceite:';

  let text = raw;
  if (analysisId !== null) {
    const specificPrefix = new RegExp('^\\[impact:\\s*' + String(analysisId) + '\\]\\s*', 'i');
    text = text.replace(specificPrefix, '').trim();
  }
  text = text.replace(/^\[impact:\s*\d+\]\s*/i, '').trim();

  if (!text.includes(marker)) {
    return { descricao: text, criterios: [] };
  }

  const parts = text.split(marker);
  const descricao = toStr(parts.shift());
  const criterios = parts
    .join(marker)
    .split('|')
    .map((x) => toStr(x))
    .filter(Boolean);

  return { descricao, criterios };
};

const suitesByChangeId = new Map();
for (const suite of testsuiteRows) {
  const changeId = toNum(suite.change_id);
  const suiteId = toNum(suite.id ?? suite.testsuite_id);
  if (!Number.isFinite(changeId) || !Number.isFinite(suiteId)) continue;
  if (!suitesByChangeId.has(changeId)) suitesByChangeId.set(changeId, new Set());
  suitesByChangeId.get(changeId).add(suiteId);
}

const testsBySuiteId = new Map();
for (const test of testRows) {
  const suiteId = toNum(test.testsuite_id);
  const desc = toStr(test.description);
  if (!Number.isFinite(suiteId) || !desc) continue;
  if (!testsBySuiteId.has(suiteId)) testsBySuiteId.set(suiteId, []);
  testsBySuiteId.get(suiteId).push(desc);
}

const codeByChangeId = new Map();
for (const row of codeChangeRows) {
  const changeId = toNum(row.change_id);
  const code = toStr(row.code);
  if (!Number.isFinite(changeId) || !code) continue;
  if (!codeByChangeId.has(changeId)) codeByChangeId.set(changeId, []);
  codeByChangeId.get(changeId).push(code);
}

const groupedChanges = [];

for (const change of changeRows) {
  const repoId = toNum(change.repo_id);
  if (!Number.isFinite(repoId)) continue;

  const repoName = repoNameById.get(repoId) || ('repo-' + String(repoId));
  if (!rebuiltImpacts[repoName]) rebuiltImpacts[repoName] = defaultRepoImpact();

  const changeId = toNum(change.id ?? change.change_id);
  const parsed = parseSummary(change.change_summary);
  const descricao = parsed.descricao || 'Mudanca sem descricao';
  const criterios = uniq(parsed.criterios);
  const codeChangesForChange = Number.isFinite(changeId) ? uniq(codeByChangeId.get(changeId) || []) : [];

  let testes = [];
  if (Number.isFinite(changeId)) {
    const suiteIds = [...(suitesByChangeId.get(changeId) || new Set())];
    for (const suiteId of suiteIds) {
      testes.push(...(testsBySuiteId.get(suiteId) || []));
    }
  }

  if (testes.length === 0) {
    testes = toArray(change.test_steps || change.testes || change.tests)
      .map((x) => toStr(x))
      .filter(Boolean);
  }

  const riscos = uniq(toArray(change.change_risks || change.riscos || change.risks));
  const duvidas = uniq(toArray(change.change_doubts || change.duvidas || change.doubts));

  rebuiltImpacts[repoName].impacto = true;
  rebuiltImpacts[repoName].mudancas.push({
    descricao,
    testes: uniq(testes),
    criterios_aceite: criterios,
    code_changes: codeChangesForChange,
  });

  if (codeChangesForChange.length > 0) {
    groupedChanges.push({
      change_id: Number.isFinite(changeId) ? changeId : null,
      repo_id: repoId,
      repo_name: repoName,
      change_summary: toStr(change.change_summary),
      code_changes: codeChangesForChange,
    });
  }

  rebuiltImpacts[repoName].riscos = uniq([...(rebuiltImpacts[repoName].riscos || []), ...riscos]);
  rebuiltImpacts[repoName].duvidas = uniq([...(rebuiltImpacts[repoName].duvidas || []), ...duvidas]);
}

const normalizeRepoImpact = (input) => {
  const info = asObj(input);
  return {
    impacto: info.impacto === true || info.impact === true || info.has_impact === true,
    mudancas: toArray(info.mudancas || info.changes).map((c) => {
      const x = asObj(c);
      return {
        descricao: toStr(x.descricao || x.description || x.desc),
        testes: uniq(toArray(x.testes || x.tests || x.test_steps)),
        criterios_aceite: uniq(toArray(x.criterios_aceite || x.acceptance_criteria || x.acceptance_criterias)),
      };
    }),
    riscos: uniq(toArray(info.riscos || info.risks)),
    duvidas: uniq(toArray(info.duvidas || info.doubts || info.questions)),
    itens: uniq(toArray(info.itens || info.items)),
  };
};

const isSpecialKey = (key) => key === 'infra' || key === 'integracoes_externas';
const rebuiltHasRepoImpacts = Object.entries(rebuiltImpacts).some(([key, info]) => {
  if (isSpecialKey(key)) return false;
  return info.impacto === true || (Array.isArray(info.mudancas) && info.mudancas.length > 0);
});

const finalImpacts = {};

if (rebuiltHasRepoImpacts) {
  const repoKeys = new Set([
    ...Object.keys(rebuiltImpacts).filter((k) => !isSpecialKey(k)),
    ...Object.keys(existingImpacts).filter((k) => !isSpecialKey(k)),
  ]);

  for (const repoKey of repoKeys) {
    const rebuilt = rebuiltImpacts[repoKey] || defaultRepoImpact();
    const existing = normalizeRepoImpact(existingImpacts[repoKey]);

    if (rebuilt.impacto || rebuilt.mudancas.length > 0) {
      finalImpacts[repoKey] = {
        impacto: true,
        mudancas: rebuilt.mudancas,
        riscos: uniq([...(rebuilt.riscos || []), ...(existing.riscos || [])]),
        duvidas: uniq([...(rebuilt.duvidas || []), ...(existing.duvidas || [])]),
      };
    } else {
      finalImpacts[repoKey] = {
        impacto: existing.impacto || false,
        mudancas: existing.mudancas || [],
        riscos: existing.riscos || [],
        duvidas: existing.duvidas || [],
      };
    }
  }
} else {
  for (const [key, value] of Object.entries(existingImpacts)) {
    if (isSpecialKey(key)) continue;
    const v = normalizeRepoImpact(value);
    finalImpacts[key] = {
      impacto: v.impacto,
      mudancas: v.mudancas,
      riscos: v.riscos,
      duvidas: v.duvidas,
    };
  }

  // Keep repos table coverage even when no impact exists.
  for (const repoName of repoNameById.values()) {
    if (!finalImpacts[repoName]) finalImpacts[repoName] = defaultRepoImpact();
  }
}

const infra = normalizeRepoImpact(existingImpacts.infra);
const integracoes = normalizeRepoImpact(existingImpacts.integracoes_externas);
finalImpacts.infra = { impacto: infra.impacto, itens: infra.itens || [] };
finalImpacts.integracoes_externas = { impacto: integracoes.impacto, itens: integracoes.itens || [] };

const criteriaMapped = [];
const aggregatedRiscos = [];
const aggregatedDuvidas = [];
for (const [repoName, infoRaw] of Object.entries(finalImpacts)) {
  if (repoName === 'infra' || repoName === 'integracoes_externas') continue;
  const info = asObj(infoRaw);
  const mudancas = toArray(info.mudancas);

  aggregatedRiscos.push(...toArray(info.riscos));
  aggregatedDuvidas.push(...toArray(info.duvidas));

  for (const m of mudancas) {
    const c = asObj(m);
    const criterios = toArray(c.criterios_aceite).map((x) => toStr(x)).filter(Boolean);
    const testes = toArray(c.testes).map((x) => toStr(x)).filter(Boolean);
    for (const criterio of criterios) {
      criteriaMapped.push({
        criterio,
        repos: [repoName],
        teste_sugerido: testes[0] || ''
      });
    }
  }
}

const existingCriteria = toArray(
  analysisBase.criterios_aceite_mapeados ||
  analysisBase.acceptance_criteria_mapped ||
  analysisBase.mapped_acceptance_criteria
);

const finalAnalysis = {
  resumo: toStr(analysisBase.resumo || analysisBase.summary || impactInsert.change_summary || 'Sem resumo'),
  viabilidade: {
    nivel: toStr(analysisBase?.viabilidade?.nivel || analysisBase?.viability?.level || impactInsert.complexity_level || 'Media') || 'Media',
    justificativa: toStr(analysisBase?.viabilidade?.justificativa || analysisBase?.viability?.justification || 'Reconstruida a partir das data-tables e contexto do fluxo.')
  },
  impactos: finalImpacts,
  criterios_aceite_mapeados: criteriaMapped.length > 0 ? criteriaMapped : existingCriteria,
  riscos: uniq([...(toArray(analysisBase.riscos || analysisBase.risks)), ...aggregatedRiscos]),
  duvidas: uniq([...(toArray(analysisBase.duvidas || analysisBase.questions)), ...aggregatedDuvidas]),
  source_analysis_id: analysisId,
};

return [{
  json: {
    ...base,
    analysis: finalAnalysis,
    grouped_changes: groupedChanges,
    impact_analysis_id: analysisId,
    persisted_at: new Date().toISOString(),
    analysis_rebuilt_from_tables: rebuiltHasRepoImpacts,
    analysis_tables_stats: {
      repos: repoRows.length,
      changes: changeRows.length,
      testsuites: testsuiteRows.length,
      tests: testRows.length,
      code_changes: codeChangeRows.length,
    },
  }
}];

const toSafeNumber = (value) => {
  if (value === undefined || value === null) return NaN;
  const s = String(value).replace(/^\uFEFF/, '').trim();
  if (!s) return NaN;
  const n = Number(s);
  return Number.isFinite(n) ? n : NaN;
};

const inputItems = $input.all();
const out = [];

for (const item of inputItems) {
  const row = item.json || {};

  if (row.skip_repo_persistence === true || String(row.skip_repo_persistence || '').toLowerCase() === 'true') {
    continue;
  }

  const repoId = toSafeNumber(row.repo_id);
  const changeSummary = String(row.change_summary || '').trim();

  if (!Number.isFinite(repoId) || !changeSummary) {
    continue;
  }

  out.push({
    json: {
      ...row,
      repo_id: repoId,
      change_summary: changeSummary,
    },
  });
}

if (out.length === 0) {
  return [{
    json: {
      skip_repo_persistence: true,
      reason: 'no_valid_change_rows_after_ensure'
    }
  }];
}

return out;

const insertedChanges = $input.all();
if (insertedChanges.length === 0) {
  return [];
}

const tryLoadSourceRows = () => {
  const candidates = ['Build Change Rows', 'Build Change Rows1', 'Build Change Rows2'];
  for (const name of candidates) {
    try {
      const rows = $items(name, 0, 0).map((i) => i.json || {});
      if (rows.length > 0) return rows;
    } catch (_e) {}
  }
  return [];
};

const sourceRows = tryLoadSourceRows();
const makeKey = (repoId, changeSummary) => Number(repoId) + '::' + String(changeSummary || '').trim();
const sourceByKey = new Map();
for (const source of sourceRows) {
  sourceByKey.set(makeKey(source.repo_id, source.change_summary), source);
}

const out = [];
for (const item of insertedChanges) {
  const inserted = item.json || {};
  const key = makeKey(inserted.repo_id, inserted.change_summary);
  const source = sourceByKey.get(key) || {};

  const changeId = Number(inserted.id);
  if (!Number.isFinite(changeId)) continue;

  const suggested = Array.isArray(source.code_changes)
    ? source.code_changes.map((x) => String(x || '').trim()).filter(Boolean)
    : [];

  out.push({
    json: {
      change_id: changeId,
      repo_id: Number(inserted.repo_id),
      repo_name: String(source.repo_name || inserted.repo_name || '').trim(),
      change_summary: String(inserted.change_summary || '').trim(),
      suggested_code_changes: suggested,
    }
  });
}

return out;

