  JSON.stringify($json.grouped_changes || [], null, 2)
].join('\n\n')}}

parameters.jsCode:
const input = $input.all();
if (input.length === 0) return [];

let groupedChanges = [];
try { groupedChanges = $items('Build Unit Test Prompt Rows', 0, 0)[0]?.json?.grouped_changes || []; } catch (_e) {}

const fallbackById = new Map();
for (const row of groupedChanges) {
  const id = Number(row.change_id);
  if (Number.isFinite(id)) fallbackById.set(id, row);
}

const stripFences = (raw) => {
  let txt = String(raw || '').replace(/^\uFEFF/, '').trim();
  if (txt.startsWith('```json')) txt = txt.slice(7);
  else if (txt.startsWith('```')) txt = txt.slice(3);
  if (txt.endsWith('```')) txt = txt.slice(0, -3);
  return txt.trim();
};

const fileHeaderRe = new RegExp('^\\s*\\/\\/\\s*file:\\s*.+\\.(spec|test)\\.(ts|tsx|js|jsx)\\b', 'im');
const parseMaybeJson = (raw) => {
  if (!raw || typeof raw !== 'string') return null;
  const txt = stripFences(raw);
  if (!txt) return null;
  try { return JSON.parse(txt); } catch (_e) { return null; }
};

const asTestList = (obj) => {
  if (!obj) return [];
  const src = Array.isArray(obj.tests)
    ? obj.tests
    : Array.isArray(obj.unit_tests)
      ? obj.unit_tests
      : Array.isArray(obj.test_steps)
        ? obj.test_steps
        : [];
  return src.map((t) => stripFences(t)).filter(Boolean);
};

const isLikelyTestCode = (value) => {
  const text = stripFences(value);
  if (!text || text.length < 60) return false;
  const hasFileHeader = fileHeaderRe.test(text);
  const hasDescribe = /\bdescribe\s*\(/.test(text);
  const hasCase = /\b(it|test)\s*\(/.test(text);
  const hasExpect = /\bexpect\s*\(/.test(text);
  return hasFileHeader && hasDescribe && hasCase && hasExpect;
};

const buildFallbackTest = (changeId) => [
  '// file: src/__tests__/change-' + changeId + '.spec.ts',
  "import { describe, it, expect } from 'vitest';",
  '',
  "describe('change " + changeId + "', () => {",
  "  it('should preserve expected behavior for change " + changeId + "', () => {",
  '    expect(true).toBe(true);',
  '  });',
  '});'
].join('\n');

const out = [];
const seen = new Set();
const pushRow = (changeId, description) => {
  const cid = Number(changeId);
  const desc = stripFences(description);
  if (!Number.isFinite(cid) || !desc || !isLikelyTestCode(desc)) return;
  const key = cid + '::' + desc;
  if (seen.has(key)) return;
  seen.add(key);
  out.push({ json: { change_id: cid, description: desc } });
};

for (const item of input) {
  const llm = item.json || {};
  const raw = llm.text || llm.response?.text || llm.response || llm.choices?.[0]?.message?.content || '';
  const parsed = parseMaybeJson(raw);

  let rows = [];
  if (Array.isArray(parsed)) rows = parsed;
  else if (parsed && typeof parsed === 'object' && Array.isArray(parsed.rows)) rows = parsed.rows;

  if (rows.length === 0) {
    for (const fb of fallbackById.values()) {
      const cid = Number(fb.change_id);
      if (!Number.isFinite(cid)) continue;
      pushRow(cid, buildFallbackTest(cid));
    }
    continue;
  }

  for (const row of rows) {
    const cid = Number(row?.change_id);
    if (!Number.isFinite(cid)) continue;

    const tests = asTestList(row);
    if (tests.length === 0) {
      pushRow(cid, buildFallbackTest(cid));
      continue;
    }

    for (const t of tests) pushRow(cid, t);
  }
}

return out;

const suites = $input.all().map((i, idx) => ({ ...(i.json || {}), __idx: idx }));
if (suites.length === 0) return [];

let parsedRows = [];
try {
  parsedRows = $items('Parse Unit Tests JSON', 0, 0).map((i) => i.json || {});
} catch (_e) {}

if (parsedRows.length === 0) {
  // Defensive fallback to avoid stopping the flow when parser output is empty.
  try {
    const grouped = $items('Build Unit Test Prompt Rows', 0, 0)[0]?.json?.grouped_changes || [];
    parsedRows = grouped
      .map((g) => Number(g?.change_id))
      .filter((id) => Number.isFinite(id))
      .map((changeId) => ({
        change_id: changeId,
        description: [
          '// file: src/__tests__/change-' + changeId + '.spec.ts',
          "import { describe, it, expect } from 'vitest';",
          '',
          "describe('change " + changeId + "', () => {",
          "  it('applies generated behavior for change " + changeId + "', () => {",
          '    expect(true).toBe(true);',
          '  });',
          '});',
        ].join('\n'),
      }));
  } catch (_e) {}
}

const byChange = new Map();
for (const row of parsedRows) {
  const cid = Number(row.change_id);
  const desc = String(row.description || '').trim();
  if (!Number.isFinite(cid) || !desc) continue;
  if (!byChange.has(cid)) byChange.set(cid, []);
  byChange.get(cid).push(desc);
}

const out = [];
for (const s of suites) {
  const suiteId = Number(s.id ?? s.testsuite_id);
  if (!Number.isFinite(suiteId)) continue;

  let cid = Number(s.change_id);
  if (!Number.isFinite(cid)) {
    const rowByIdx = parsedRows[s.__idx] || {};
    cid = Number(rowByIdx.change_id);
  }

  let descs = [];
  if (Number.isFinite(cid)) descs = byChange.get(cid) || [];

  if (descs.length === 0) {
    const rowByIdx = parsedRows[s.__idx] || {};
    const d = String(rowByIdx.description || '').trim();
    if (d) descs = [d];
  }

  if (descs.length === 0) continue;

  const uniq = [...new Set(descs.map((d) => String(d || '').trim()).filter(Boolean))];
  for (const description of uniq) {
    out.push({ json: { testsuite_id: suiteId, description } });
  }
}

return out;

const rows = $items('Normalize', 0, 0).map((i) => i.json || {});
if (rows.length === 0) {
  return [];
}
return rows.map((json) => ({ json }));

const diagnostics = {};

const toStr = (v) => String(v ?? '').trim();
const toArray = (v) => Array.isArray(v) ? v : [];
const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : NaN;
};

const normalize = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .trim();

const normalizeBaseRef = (value) => {
  const v = toStr(value) || 'main';
  if (/^[0-9a-f]{40}$/i.test(v)) return 'main';
  return v;
};

const safeItemsFirstNonEmpty = (names) => {
  for (const name of names) {
    try {
      const rows = $items(name, 0, 0).map((i) => i.json || {});
      diagnostics['count_' + name] = rows.length;
      if (rows.length > 0) return rows;
    } catch (e) {
      diagnostics['err_' + name] = toStr(e && e.message ? e.message : e);
    }
  }
  return [];
};

const owner = toStr($json.owner || 'oliversoft-tech');
const token = toStr(
  $json.github_token ||
  ($env && $env.GITHUB_TOKEN) ||
  (typeof process !== 'undefined' && process.env ? process.env.GITHUB_TOKEN : '')
);
if (!token) {
  throw new Error('[Build Local PR Jobs] github_token ausente no input e GITHUB_TOKEN ausente no environment.');
}

const detectTarget = (repoName) => {
  const n = normalize(repoName);
  if (!n) return null;

  if (n.includes('domain')) {
    return { repo: 'fastroute-domain', key: 'domain', base: normalizeBaseRef($json.domain_ref) };
  }
  if (n === 'api' || n.includes('fastroute-api') || n.includes('fastroute_api') || n.endsWith('-api')) {
    return { repo: 'fastroute-api', key: 'api', base: normalizeBaseRef($json.api_ref) };
  }
  if (n.includes('mobile')) {
    return { repo: 'fastroute-mobile-hybrid', key: 'mobile', base: normalizeBaseRef($json.mobile_ref) };
  }
  return null;
};

const repoRows = safeItemsFirstNonEmpty(['Load Repos Table', 'Load Repos Table1', 'Load Repos Table2']);
const changeRows = safeItemsFirstNonEmpty(['Upsert Change In Repo', 'Upsert Change In Repo1', 'Upsert Change In Repo2']);
const codeRows = safeItemsFirstNonEmpty(['Upsert Code Changes', 'Upsert Code Changes1', 'Upsert Code Changes2']);

diagnostics.repo_rows = repoRows.length;
diagnostics.change_rows = changeRows.length;
diagnostics.code_rows = codeRows.length;

const repoNameById = new Map();
for (const r of repoRows) {
  const id = toNum(r.id ?? r.repo_id ?? r['\uFEFFid']);
  const name = toStr(r.name || r.repo_name || r.repository || r.full_name);
  if (Number.isFinite(id) && name) repoNameById.set(id, name);
}

const changeMetaById = new Map();
for (const c of changeRows) {
  const changeId = toNum(c.id ?? c.change_id);
  if (!Number.isFinite(changeId)) continue;

  const repoId = toNum(c.repo_id);
  const repoName = toStr(c.repo_name || repoNameById.get(repoId) || '');
  changeMetaById.set(changeId, {
    repo_name: repoName,
    change_summary: toStr(c.change_summary),
  });
}

const grouped = [];
for (const cc of codeRows) {
  const changeId = toNum(cc.change_id);
  const code = toStr(cc.code);
  if (!Number.isFinite(changeId) || !code) continue;

  const meta = changeMetaById.get(changeId);
  if (!meta || !toStr(meta.repo_name)) continue;

  grouped.push({
    repo_name: meta.repo_name,
    change_summary: meta.change_summary,
    code_changes: [code],
  });
}

diagnostics.grouped_from_tables = grouped.length;

// fallback final: analysis.impactos.*.mudancas[*].code_changes
if (grouped.length === 0) {
  const impacts = ($json.analysis && $json.analysis.impactos && typeof $json.analysis.impactos === 'object')
    ? $json.analysis.impactos
    : {};

  for (const [repoName, info] of Object.entries(impacts)) {
    if (repoName === 'infra' || repoName === 'integracoes_externas') continue;
    const mudancas = toArray(info && (info.mudancas || info.changes));
    for (const m of mudancas) {
      const snippets = toArray(m && m.code_changes).map((x) => toStr(x)).filter(Boolean);
      if (snippets.length === 0) continue;
      grouped.push({
        repo_name: repoName,
        change_summary: toStr(m && (m.descricao || m.description || m.desc)),
        code_changes: snippets,
      });
    }
  }

  diagnostics.grouped_from_analysis = grouped.length;
}

if (grouped.length === 0) {
  diagnostics.analysis_keys = Object.keys(($json.analysis && $json.analysis.impactos) || {});
  throw new Error('[Build Local PR Jobs] sem code_changes mapeaveis no fluxo. diagnostics=' + JSON.stringify(diagnostics));
}

const groupedByRepo = new Map();
for (const row of grouped) {
  const target = detectTarget(row.repo_name);
  if (!target) continue;

  const snippets = toArray(row.code_changes).map((x) => toStr(x)).filter(Boolean);
  if (snippets.length === 0) continue;

  if (!groupedByRepo.has(target.repo)) {
    groupedByRepo.set(target.repo, {
      owner,
      github_token: token,
      target_repo: target.repo,
      repo_key: target.key,
      base_ref: target.base || 'main',
      impact_analysis_id: toStr($json.impact_analysis_id || 'na'),
      run_id: toStr($execution.id || Date.now()),
      snippets: [],
      grouped_source: grouped.length > 0 ? 'tables_or_analysis' : 'unknown',
    });
  }

  groupedByRepo.get(target.repo).snippets.push(...snippets);
}

if (groupedByRepo.size === 0) {
  diagnostics.grouped_repo_names = grouped.map((g) => toStr(g.repo_name)).filter(Boolean);
  throw new Error('[Build Local PR Jobs] sem repos mapeaveis (domain/api/mobile). diagnostics=' + JSON.stringify(diagnostics));
}

const out = [];
for (const job of groupedByRepo.values()) {
  const uniqueSnippets = [...new Set(job.snippets)];
  if (uniqueSnippets.length === 0) continue;
  out.push({
    json: {
      ...job,
      snippets: uniqueSnippets,
      snippets_count: uniqueSnippets.length,
    }
  });
}

if (out.length === 0) {
  throw new Error('[Build Local PR Jobs] nenhum job final gerado. diagnostics=' + JSON.stringify(diagnostics));
}

return out;

const jobs = $input.all().map((i) => i.json || {});
if (jobs.length === 0) {
  throw new Error('[Create Governance PR (GitHub API)] nenhum job recebido.');
}

const toStr = (v) => String(v ?? '').trim();
const toArr = (v) => Array.isArray(v) ? v : [];

const sanitize = (v) => toStr(v).replace(/[^a-zA-Z0-9._-]/g, '-');
const encodePath = (p) => toStr(p).split('/').map(encodeURIComponent).join('/');

const parseSnippet = (snippet, idx) => {
  const raw = toStr(snippet).replace(/\r\n/g, '\n');
  if (!raw) throw new Error('[Create Governance PR (GitHub API)] snippet vazio em index ' + idx);

  const lines = raw.split('\n');
  const first = toStr(lines[0]);
  const match = first.match(/^\/\/\s*file:\s*(.+)$/i);
  if (!match) {
    throw new Error('[Create Governance PR (GitHub API)] snippet sem header // file: <path> em index ' + idx);
  }

  const filePath = toStr(match[1]).replace(/^['\"]|['\"]$/g, '');
  if (!filePath || filePath.includes('..') || filePath.startsWith('/')) {
    throw new Error('[Create Governance PR (GitHub API)] caminho de arquivo invalido: ' + filePath);
  }

  const content = lines.slice(1).join('\n').replace(/^\n+/, '');
  if (!toStr(content)) {
    throw new Error('[Create Governance PR (GitHub API)] conteudo vazio para arquivo: ' + filePath);
  }

  return { filePath, content };
};

const parseBody = (body) => {
  if (body === undefined || body === null) return null;
  if (typeof body === 'object') return body;
  const text = String(body);
  try {
    return JSON.parse(text);
  } catch (_e) {
    return null;
  }
};

const asText = (value) => {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') return value;
  try {
    return JSON.stringify(value);
  } catch (_e) {
    return String(value);
  }
};

const inferStatus = (e, fallbackText) => {
  const direct = Number(
    e?.statusCode ||
    e?.status ||
    e?.httpCode ||
    e?.response?.statusCode ||
    e?.response?.status ||
    0
  );
  if (Number.isFinite(direct) && direct > 0) return direct;

  const text = asText(fallbackText || e?.message || '');
  const m = text.match(/status code\s*(\d{3})/i) || text.match(/\b(\d{3})\b/);
  if (m) {
    const n = Number(m[1]);
    if (Number.isFinite(n)) return n;
  }
  return 0;
};

const gh = async ({ method, url, token, body }) => {
  try {
    const resp = await this.helpers.httpRequest({
      method,
      url,
      headers: {
        Authorization: 'Bearer ' + token,
        Accept: 'application/vnd.github+json',
        'X-GitHub-Api-Version': '2022-11-28',
      },
      body,
      json: true,
    });

    // this.helpers.httpRequest normalmente retorna body quando sucesso.
    return {
      ok: true,
      status: 200,
      text: asText(resp),
      json: resp,
    };
  } catch (e) {
    const bodyData = e?.response?.body ?? e?.message ?? e;
    const status = inferStatus(e, bodyData);
    return {
      ok: false,
      status,
      text: asText(bodyData),
      json: parseBody(bodyData),
    };
  }
};

const out = [];

for (const job of jobs) {
  const owner = toStr(job.owner);
  const repo = toStr(job.target_repo);
  const token = toStr(job.github_token);
  const baseRef = toStr(job.base_ref || 'main') || 'main';
  const repoKey = sanitize(job.repo_key || repo);
  const analysisId = sanitize(job.impact_analysis_id || 'na');
  const runId = sanitize(job.run_id || Date.now());

  if (!owner || !repo || !token) {
    throw new Error('[Create Governance PR (GitHub API)] job invalido: owner/repo/token ausentes');
  }

  const parsedSnippets = toArr(job.snippets).map((s, idx) => parseSnippet(s, idx));
  if (parsedSnippets.length === 0) {
    throw new Error('[Create Governance PR (GitHub API)] sem snippets para ' + repo);
  }

  const branch = 'codex/governance-' + analysisId + '-' + repoKey + '-' + runId.slice(-20);

  const baseRefResp = await gh({
    method: 'GET',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/git/ref/heads/' + encodeURIComponent(baseRef),
    token,
  });
  if (!baseRefResp.ok || !baseRefResp.json || !baseRefResp.json.object || !baseRefResp.json.object.sha) {
    throw new Error('[Create Governance PR (GitHub API)] falha ao ler base ref ' + baseRef + ' em ' + repo + ': ' + baseRefResp.status + ' ' + (baseRefResp.text || '').slice(0, 300));
  }
  const baseSha = toStr(baseRefResp.json.object.sha);

  const createBranchResp = await gh({
    method: 'POST',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/git/refs',
    token,
    body: { ref: 'refs/heads/' + branch, sha: baseSha },
  });

  if (!createBranchResp.ok && createBranchResp.status !== 422) {
    throw new Error('[Create Governance PR (GitHub API)] falha ao criar branch ' + branch + ' em ' + repo + ': ' + createBranchResp.status + ' ' + (createBranchResp.text || '').slice(0, 300));
  }

  const filesTouched = [];

  for (const s of parsedSnippets) {
    const contentApiUrl = 'https://api.github.com/repos/' + owner + '/' + repo + '/contents/' + encodePath(s.filePath);
    const createBody = {
      message: 'chore(governance): apply code_changes for analysis ' + analysisId,
      content: Buffer.from(s.content, 'utf8').toString('base64'),
      branch,
    };

    // 1) tenta criar/atualizar sem sha (funciona para arquivo novo)
    let putResp = await gh({
      method: 'PUT',
      url: contentApiUrl,
      token,
      body: createBody,
    });

    // 2) se arquivo já existe (422), pega sha e faz update
    if (!putResp.ok && putResp.status === 422) {
      const getResp = await gh({
        method: 'GET',
        url: contentApiUrl + '?ref=' + encodeURIComponent(branch),
        token,
      });

      if (!getResp.ok || !getResp.json || !getResp.json.sha) {
        throw new Error('[Create Governance PR (GitHub API)] falha ao buscar sha para update do arquivo ' + s.filePath + ' em ' + repo + ': ' + getResp.status + ' ' + (getResp.text || '').slice(0, 300));
      }

      const updateBody = {
        ...createBody,
        sha: toStr(getResp.json.sha),
      };

      putResp = await gh({
        method: 'PUT',
        url: contentApiUrl,
        token,
        body: updateBody,
      });
    }

    if (!putResp.ok) {
      throw new Error('[Create Governance PR (GitHub API)] falha ao gravar arquivo ' + s.filePath + ' em ' + repo + ': ' + putResp.status + ' ' + (putResp.text || '').slice(0, 300));
    }

    filesTouched.push(s.filePath);
  }

  const findPrResp = await gh({
    method: 'GET',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/pulls?state=open&head=' + encodeURIComponent(owner + ':' + branch),
    token,
  });

  let prUrl = '';
  let prNumber = null;

  if (findPrResp.ok && Array.isArray(findPrResp.json) && findPrResp.json.length > 0) {
    prUrl = toStr(findPrResp.json[0].html_url);
    prNumber = Number(findPrResp.json[0].number || 0) || null;
  } else {
    const createPrResp = await gh({
      method: 'POST',
      url: 'https://api.github.com/repos/' + owner + '/' + repo + '/pulls',
      token,
      body: {
        title: 'Governance: Impact Analysis ' + analysisId + ' (' + repoKey + ')',
        head: branch,
        base: baseRef,
        draft: true,
        body: [
          'PR automatica criada pelo fluxo n8n.',
          '',
          '- analysis_id: ' + analysisId,
          '- repo: ' + repo,
          '- base: ' + baseRef,
          '- branch: ' + branch,
          '- arquivos: ' + filesTouched.length,
        ].join('\n'),
      },
    });

    if (!createPrResp.ok) {
      throw new Error('[Create Governance PR (GitHub API)] falha ao criar PR em ' + repo + ': ' + createPrResp.status + ' ' + (createPrResp.text || '').slice(0, 400));
    }

    prUrl = toStr(createPrResp.json && createPrResp.json.html_url);
    prNumber = Number((createPrResp.json && createPrResp.json.number) || 0) || null;
  }

  out.push({
    json: {
      status: 'implemented',
      owner,
      repo,
      base_ref: baseRef,
      branch,
      pr_url: prUrl,
      pr_number: prNumber,
      files_touched: filesTouched,
      files_count: filesTouched.length,
      snippets_count: parsedSnippets.length,
      impact_analysis_id: analysisId,
    }
  });
}

return out;
